example.code:
# .github/workflows/release.yml (provider)
- name: can-i-deploy
  env: { PACT_BROKER_BASE_URL: ${{ secrets.PACT_BROKER }} }
  run: |
    pact-broker can-i-deploy \
      --pacticipant billing-api --version ${{ github.sha }} \
      --to-environment production --retry-while-unknown 6
- name: publish image
  if: success()
  run: docker push billing-api:${{ github.sha }}

# Provider runs verification, then ignores the result
- run: pact-verifier --provider billing-api || true
- run: docker push billing-api:${{ github.sha }}
